// Numbering: w:nsid, w:multiLevelType, w:tmpl are required by Word.
// Bullet uses Symbol font char \uF0B7 (the solid bullet in Symbol encoding).
// Each ol block gets its own numId (2, 3, 4, …) so Word resets the counter.
function buildNumberingXml(olStartNums) {
  const nums = [`<w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num>`];
  for (let i = 0; i < olStartNums.length; i++) {
    nums.push(
      `<w:num w:numId="${i + 2}">` +
        `<w:abstractNumId w:val="1"/>` +
        `<w:lvlOverride w:ilvl="0"><w:startOverride w:val="${olStartNums[i]}"/></w:lvlOverride>` +
      `</w:num>`
    );
  }
  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n` +
    `<w:numbering ${NSMAP}>\n` +
    `  <w:abstractNum w:abstractNumId="0">\n` +
    `    <w:nsid w:val="00000001"/>\n` +
    `    <w:multiLevelType w:val="singleLevel"/>\n` +
    `    <w:tmpl w:val="00000001"/>\n` +
    `    <w:lvl w:ilvl="0">\n` +
    `      <w:start w:val="1"/>\n` +
    `      <w:numFmt w:val="bullet"/>\n` +
    `      <w:lvlText w:val="\uF0B7"/>\n` +
    `      <w:lvlJc w:val="left"/>\n` +
    `      <w:pPr><w:tabs><w:tab w:val="num" w:pos="360"/></w:tabs><w:ind w:left="360" w:hanging="360"/></w:pPr>\n` +
    `      <w:rPr><w:rFonts w:ascii="Symbol" w:hAnsi="Symbol" w:hint="default"/></w:rPr>\n` +
    `    </w:lvl>\n` +
    `  </w:abstractNum>\n` +
    `  <w:abstractNum w:abstractNumId="1">\n` +
    `    <w:nsid w:val="00000002"/>\n` +
    `    <w:multiLevelType w:val="singleLevel"/>\n` +
    `    <w:tmpl w:val="00000002"/>\n` +
    `    <w:lvl w:ilvl="0">\n` +
    `      <w:start w:val="1"/>\n` +
    `      <w:numFmt w:val="decimal"/>\n` +
    `      <w:lvlText w:val="%1."/>\n` +
    `      <w:lvlJc w:val="left"/>\n` +
    `      <w:pPr><w:tabs><w:tab w:val="num" w:pos="360"/></w:tabs><w:ind w:left="360" w:hanging="360"/></w:pPr>\n` +
    `    </w:lvl>\n` +
    `  </w:abstractNum>\n` +
    nums.join('\n') + '\n' +
    `</w:numbering>`;
}

// settings.xml: required by Word; without it Word may report corrupt content.
const SETTINGS_XML = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:settings ${NSMAP}>
  <w:zoom w:val="100"/>
  <w:defaultTabStop w:val="720"/>
  <w:characterSpacingControl w:val="doNotCompress"/>
  <w:compat>
    <w:compatSetting w:name="compatibilityMode" w:uri="http://schemas.microsoft.com/office/word" w:val="15"/>
    <w:compatSetting w:name="overrideTableStyleFontSizeAndJustification" w:uri="http://schemas.microsoft.com/office/word" w:val="1"/>
    <w:compatSetting w:name="enableOpenTypeFeatures" w:uri="http://schemas.microsoft.com/office/word" w:val="1"/>
    <w:compatSetting w:name="doNotFlipMirrorIndents" w:uri="http://schemas.microsoft.com/office/word" w:val="1"/>
  </w:compat>
</w:settings>`;

// ── ASSEMBLE ─────────────────────────────────────────────────────────
try {
  const blocks = parseBlocks(input);
  const { bodyXml, relsXml, olStartNums } = buildDocXml(blocks);

  const docXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document ${NSMAP}>
  <w:body>${bodyXml}<w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="1440" w:right="1080" w:bottom="1440" w:left="1080" w:header="720" w:footer="720" w:gutter="0"/></w:sectPr></w:body>
</w:document>`;

  const docRelsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"    Target="styles.xml"/>
  <Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering" Target="numbering.xml"/>
  <Relationship Id="rId3s" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/settings" Target="settings.xml"/>
  ${relsXml}
</Relationships>`;

  const ctXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Default Extension="xml"  ContentType="application/xml"/>
  <Override PartName="/word/document.xml"  ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>
  <Override PartName="/word/styles.xml"    ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>
  <Override PartName="/word/numbering.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"/>
  <Override PartName="/word/settings.xml"  ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.settings+xml"/>
</Types>`;

  const rootRelsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>
</Relationships>`;

  const zipBytes = buildZip([
    { name: '[Content_Types].xml',         data: enc(ctXml) },
    { name: '_rels/.rels',                  data: enc(rootRelsXml) },
    { name: 'word/document.xml',            data: enc(docXml) },
    { name: 'word/_rels/document.xml.rels', data: enc(docRelsXml) },
    { name: 'word/styles.xml',              data: enc(STYLES_XML) },
    { name: 'word/numbering.xml',           data: enc(buildNumberingXml(olStartNums)) },
    { name: 'word/settings.xml',            data: enc(SETTINGS_XML) },
  ]);

  let b64 = '';
  const CHUNK = 8192;
  for (let i = 0; i < zipBytes.length; i += CHUNK)
    b64 += String.fromCharCode(...zipBytes.subarray(i, i + CHUNK));

  return { output: btoa(b64), outputEncoding: 'base64', outputLanguage: 'binary' };
} catch (err) {
  return { output: '', error: err instanceof Error ? err.message : String(err) };
}
